func solve(s: String, k: Int64) -> String {
    var result = [Character]()
    for char in s {
        if char.isLetter {
            result.append(char)
        } else if char == "*" {
            if !result.isEmpty {
                result.removeLast()
            }
        } else if char == "#" {
            result.append(contentsOf: result)
        } else if char == "%" {
            result = result.reversed()
        }
    }
    if k < Int64(result.count) {
        return String(result[Int(k)])
    } else {
        return "."
    }
}
